// Angular imports
import { Component, inject, OnInit, signal, DestroyRef } from '@angular/core';
import { ActivatedRoute } from '@angular/router';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';

// Third-party imports
import { AccordionModule } from 'primeng/accordion';
import { DividerModule } from 'primeng/divider';

// Application imports
import { DistributorDetailsComponent } from '../distributor-details/distributor-details.component';
import { CustomizeDistributorComponent } from '../customize-distributor/customize-distributor.component';
import { DistributorAddressComponent } from '../distributor-address/distributor-address.component';
import { DistributorSslCertificatesComponent } from '../distributor-ssl-certificates/distributor-ssl-certificates.component';
import { DistributorResponse } from '../../../../../../api';
import { DistributorSettingsComponent } from '../distributor-settings/distributor-settings.component';
import { DistributorNotificationSettingsComponent } from '../distributor-notification-settings/distributor-notification-settings.component';
import { DistributorExternalAuthenticationComponent } from '../distributor-external-authentication/distributor-external-authentication.component';

@Component({
  selector: 'app-distributor-details-container',
  imports: [
    AccordionModule,
    DividerModule,
    // Information
    DistributorDetailsComponent,
    CustomizeDistributorComponent,
    DistributorAddressComponent,
    DistributorSslCertificatesComponent,
    //Settings
    DistributorSettingsComponent,
    DistributorNotificationSettingsComponent,
    DistributorExternalAuthenticationComponent,
  ],
  templateUrl: './distributor-details-container.component.html',
  styleUrl: './distributor-details-container.component.scss',
})
export class DistributorDetailsContainerComponent implements OnInit {
  private readonly route = inject(ActivatedRoute);
  private readonly destroyRef = inject(DestroyRef);

  distributor = signal<DistributorResponse | null>(null);

  ngOnInit(): void {
    this.route.parent?.parent?.data
      .pipe(takeUntilDestroyed(this.destroyRef))
      .subscribe({
        next: (data) => this.distributor.set(data['distributor']),
      });
  }
}
